-	newCount := 0
-	exactCount := 0
-	collisionCount := 0
-	for _, incoming := range issues {
-		existing, ok := dbByID[incoming.ID]
-		if !ok || existing == nil {
-			newCount++
-			continue
-		}
-		// Exact content match is idempotent.
-		if existing.ContentHash != "" && incoming.ContentHash != "" && existing.ContentHash == incoming.ContentHash {
