-// hierarchyDepth returns the number of hierarchical segments in an ID.
-// Examples:
-// - "bd-abc" -> 0
-// - "bd-abc.1" -> 1
-// - "bd-abc.1.2" -> 2
-func hierarchyDepth(id string) int {
-	depth := 0
-	cur := id
-	for {
-		isHier, parent := isHierarchicalID(cur)
-		if !isHier {
-			return depth
-		}
-		depth++
-		cur = parent
-	}
-}
