-			prefix = strings.TrimSpace(prefix)
-			if prefix == "" {
-				continue
-			}
-			// Normalize: remove trailing - if present (we match without it)
-			prefix = strings.TrimSuffix(prefix, "-")
-			allowed[prefix] = true
-		}
-	}
-
-	// Load prefixes from routes.jsonl for multi-rig setups (Gas Town)
