-
-	// Create an issue with pinned=true (simulates `bd pin` command)
-	pinnedIssue := &types.Issue{
-		ID:        "test-abc123",
-		Title:     "Pinned Issue",
-		Status:    types.StatusOpen,
-		Priority:  2,
-		IssueType: types.TypeTask,
-		Pinned:    true, // This is set by `bd pin`
-		CreatedAt: time.Now().Add(-time.Hour),
